final:
module RefModule(rest , A, B, Out);input rest ; 
	input [15:0] A , B ; 
	output [15:0] Out ; 
  wire _tap_rest = rest & {1{1'b1}};


	reg [15:0] Out_register ; 
	assign Out = Out_register ; 
always @(rest , A, B) begin 

	if (rest) 
		Out_register <= 0 ; 
	else 
		Out_register <= A + B ; 

	end
endmodule
